'use client';

import { forwardRef } from 'react';
import { useComponentConfig } from '../config-provider/context';
import BadgeUI from './BadgeUI';
import type { BadgeProps } from './types';

const Badge = forwardRef<HTMLDivElement, BadgeProps>((props, ref) => {
  const config = useComponentConfig('badge');

  const mergedProps = {
    ...config,
    ...props
  };

  return (
    <BadgeUI
      {...mergedProps}
      ref={ref}
    />
  );
});

Badge.displayName = 'Badge';

export default Badge;

import { forwardRef } from 'react';
import { cn } from '@/lib/utils';
import { badgeVariants } from './badge-variants';
import type { BadgeContentProps } from './types';

const BadgeContent = forwardRef<HTMLSpanElement, BadgeContentProps>((props, ref) => {
  const { className, color, position, size, ...rest } = props;

  const { content } = badgeVariants({ color, position, size });

  const mergedCls = cn(content(), className);

  return (
    <span
      className={mergedCls}
      data-slot="badge-content"
      ref={ref}
      {...rest}
    />
  );
});

BadgeContent.displayName = 'BadgeContent';

export default BadgeContent;

import { forwardRef } from 'react';
import { cn } from '@/lib/utils';
import { badgeVariants } from './badge-variants';
import type { BadgeRootProps } from './types';

const BadgeRoot = forwardRef<HTMLDivElement, BadgeRootProps>((props, ref) => {
  const { className, ...rest } = props;

  const { root } = badgeVariants();

  const mergedCls = cn(root(), className);

  return (
    <div
      className={mergedCls}
      data-slot="badge-root"
      ref={ref}
      {...rest}
    />
  );
});

BadgeRoot.displayName = 'BadgeRoot';

export default BadgeRoot;

import { forwardRef } from 'react';
import BadgeContent from './BadgeContent';
import BadgeRoot from './BadgeRoot';
import type { BadgeProps } from './types';

const BadgeUI = forwardRef<HTMLDivElement, BadgeProps>((props, ref) => {
  const { children, className, classNames, color, content, open = true, position, size, ...rest } = props;

  return (
    <BadgeRoot
      className={className || classNames?.root}
      ref={ref}
      {...rest}
    >
      {children}

      {open
        ? (
          <BadgeContent
            className={classNames?.content}
            color={color}
            position={position}
            size={size}
          >
            {content}
          </BadgeContent>
        )
        : null}
    </BadgeRoot>
  );
});

BadgeUI.displayName = 'BadgeUI';

export default BadgeUI;

import { tv } from 'tailwind-variants';
import type { VariantProps } from 'tailwind-variants';

export const badgeVariants = tv({
  defaultVariants: {
    color: 'primary',
    position: 'top-right',
    size: 'md'
  },
  slots: {
    content: `absolute flex justify-center items-center whitespace-nowrap rounded-full transform`,
    root: 'relative'
  },
  variants: {
    color: {
      accent: {
        content: 'bg-accent text-accent-foreground'
      },
      carbon: {
        content: 'bg-carbon text-carbon-foreground'
      },
      destructive: {
        content: 'bg-destructive text-destructive-foreground'
      },
      info: {
        content: 'bg-info text-info-foreground'
      },
      primary: {
        content: 'bg-primary text-primary-foreground'
      },
      secondary: {
        content: 'bg-secondary text-secondary-foreground'
      },
      success: {
        content: 'bg-success text-success-foreground'
      },
      warning: {
        content: 'bg-warning text-warning-foreground'
      }
    },
    position: {
      'bottom-left': {
        content: 'left-0 bottom-0 -translate-x-1/2 translate-y-1/2'
      },
      'bottom-right': {
        content: 'right-0 bottom-0 translate-x-1/2 translate-y-1/2'
      },
      'top-left': {
        content: 'left-0 top-0 -translate-x-1/2 -translate-y-1/2'
      },
      'top-right': {
        content: 'right-0 top-0 translate-x-1/2 -translate-y-1/2'
      }
    },
    size: {
      '2xl': {
        content: `min-h-5 px-2.5 text-base leading-relaxed`
      },
      'lg': {
        content: `min-h-3.5 px-1.75 text-xs leading-relaxed`
      },
      'md': {
        content: `min-h-3 px-1.5 text-2xs leading-relaxed`
      },
      'sm': {
        content: `min-h-2.5 px-1.25 text-3xs leading-relaxed`
      },
      'xl': {
        content: `min-h-4 px-2 text-sm leading-relaxed`
      },
      'xs': {
        content: `min-h-2 px-1 text-4xs leading-relaxed`
      }
    }
  }
});

type BadgeVariants = VariantProps<typeof badgeVariants>;

export type BadgePosition = NonNullable<BadgeVariants['position']>;

export type BadgeSlots = keyof typeof badgeVariants.slots;

export { default as Badge } from './Badge';
export { default as BadgeContent } from './BadgeContent';
export { default as BadgeRoot } from './BadgeRoot';

export * from './types';

import type { HTMLComponentProps, ClassValue, ThemeColor, ThemeSize } from '@/types/shared';
import type { BadgePosition, BadgeSlots } from './badge-variants';

/**
 * Props for the badge root container component.
 * Serves as the main wrapper for the badge element.
 */
export type BadgeRootProps = HTMLComponentProps<'div'>;

/**
 * Props for the badge content component.
 * Controls the styling and appearance of the badge's displayed content.
 */
export interface BadgeContentProps extends HTMLComponentProps<'span'> {
  /**
   * Theme color for the badge.
   * Determines the visual styling and background color.
   */
  color?: ThemeColor;

  /**
   * Position where the badge is placed.
   * Affects the badge's layout and positioning within its container.
   */
  position?: BadgePosition;

  /**
   * Size variant for the badge.
   * Controls the overall dimensions and padding.
   */
  size?: ThemeSize;
}

/**
 * Class names for different slots in the badge component.
 * Allows customizing styles for specific parts of the badge.
 */
export type BadgeUi = Partial<Record<BadgeSlots, ClassValue>>;

/**
 * Props for the main Badge component.
 * Combines root and content properties with visibility control.
 *
 * @example
 * ```tsx
 * <Badge
 *   color="blue"
 *   size="md"
 *   position="left"
 *   content="Label"
 *   open={true}
 * />
 * ```
 */
export interface BadgeProps
  extends Omit<BadgeRootProps, 'color' | 'content'>,
  Pick<BadgeContentProps, 'color' | 'position' | 'size'> {
  /**
   * Custom class names for different badge UI slots.
   * Allows fine-grained styling of badge components.
   */
  classNames?: BadgeUi;

  /**
   * The content to display inside the badge.
   * Can be text, icons, or any React node.
   */
  content?: React.ReactNode;

  /**
   * Controls the visibility/open state of the badge.
   * When true, the badge is displayed; when false, it may be hidden or collapsed.
   */
  open?: boolean;
}

export { BadgePosition };
